import { readFile, writeFile } from "node:fs/promises";
import { fileURLToPath } from "node:url";
import { compile } from "json-schema-to-typescript";

const rootUrl = new URL("../", import.meta.url);
const schemaUrl = new URL("schema.json", rootUrl);
const outputUrl = new URL("packages/types/index.d.ts", rootUrl);
const checkOnly = process.argv.includes("--check");

const schema = JSON.parse(await readFile(schemaUrl, "utf8"));
const generated = await compile(schema, "AgentTrailRecord", {
  bannerComment:
    "/*\n * Generated from schema.json by scripts/generate-types.ts.\n * Do not edit this file manually.\n */",
  style: {
    bracketSpacing: true,
    printWidth: 100,
    semi: true,
    singleQuote: false,
    tabWidth: 2,
    trailingComma: "all",
    useTabs: false,
  },
});

if (checkOnly) {
  const existing = await readFile(outputUrl, "utf8").catch(() => "");

  if (existing !== generated) {
    console.error(`${fileURLToPath(outputUrl)} is stale. Run bun run generate:types.`);
    process.exit(1);
  }
} else {
  await writeFile(outputUrl, generated);
}
